def expression_filter(expr: str) -> Callable[[LogEntry], bool]:
    """Filter by a Python expression where `entry` is the LogEntry.

    Uses ast.parse + compile with restricted globals to avoid eval()
    security risks. Only attribute access, comparisons, arithmetic,
    and boolean operations are allowed.

    Examples:
        "entry.status >= 500"
        "entry.bytes > 1024 and entry.method == 'GET'"
    """
    # Pre-compile the expression to catch syntax errors early
    try:
        tree = ast.parse(expr, mode="eval")
