    def pred(entry: LogEntry) -> bool:
        return bool(eval(code, {"__builtins__": {}}, {"entry": entry}))
    return pred


def _validate_safe_ast(node: ast.AST) -> None:
    """Recursively validate that an AST tree contains only safe node types.

    Prevents access to arbitrary attributes, function calls, imports, etc.
    """
    safe_nodes = {
        ast.Expression, ast.Module,
        ast.Attribute, ast.Name, ast.Constant,
        ast.Compare, ast.Eq, ast.NotEq, ast.Lt, ast.LtE, ast.Gt, ast.GtE,
