            raise ValueError(
                f"Unsafe expression node: {type(child).__name__}. "
                "Only comparisons, arithmetic, and boolean operations are allowed."
            )

    # Additional check: only allow 'entry' as the root Name
    for node in ast.walk(node):
        if isinstance(node, ast.Name) and node.id != "entry":
